import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Container, TextField, Button, Typography, Box, Paper, MenuItem } from '@mui/material';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';

const categories = [
  { value: 'books', label: '📚 كتب' },
  { value: 'notes', label: '📝 ملازم' },
  { value: 'tools', label: '🔧 أدوات' },
  { value: 'electronics', label: '💻 إلكترونيات' },
  { value: 'other', label: '📦 أخرى' }
];

export default function AddProduct() {
  const { token, user } = useAuth();
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    price: '',
    category: 'books',
    condition: 'used'
  });
  const [images, setImages] = useState([]);
  const [error, setError] = useState('');

  const handleImageChange = (e) => {
    setImages(Array.from(e.target.files));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const data = new FormData();
    data.append('title', formData.title);
    data.append('description', formData.description);
    data.append('price', formData.price);
    data.append('category', formData.category);
    data.append('condition', formData.condition);
    data.append('university', user.university);

    images.forEach(img => {
      data.append('images', img);
    });

    try {
      await axios.post('http://localhost:5000/api/products', data, {
        headers: { 
          Authorization: `Bearer ${token}`,
          'Content-Type': 'multipart/form-data'
        }
      });
      alert('✅ تم إضافة المنتج بنجاح!');
      navigate('/');
    } catch (error) {
      setError(error.response?.data?.message || 'حدث خطأ');
    }
  };

  if (!user) {
    navigate('/login');
    return null;
  }

  return (
    <Container maxWidth="sm" sx={{ py: 4 }}>
      <Paper elevation={3} sx={{ p: 4 }}>
        <Typography variant="h4" gutterBottom align="center">➕ إضافة منتج جديد</Typography>

        {error && <Typography color="error" align="center" sx={{ mb: 2 }}>{error}</Typography>}

        <Box component="form" onSubmit={handleSubmit} sx={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
          <TextField
            label="اسم المنتج"
            required
            value={formData.title}
            onChange={(e) => setFormData({...formData, title: e.target.value})}
          />

          <TextField
            label="الوصف"
            multiline
            rows={3}
            required
            value={formData.description}
            onChange={(e) => setFormData({...formData, description: e.target.value})}
          />

          <TextField
            label="السعر (ر.س)"
            type="number"
            required
            value={formData.price}
            onChange={(e) => setFormData({...formData, price: e.target.value})}
          />

          <TextField
            select
            label="الفئة"
            value={formData.category}
            onChange={(e) => setFormData({...formData, category: e.target.value})}
          >
            {categories.map(cat => (
              <MenuItem key={cat.value} value={cat.value}>{cat.label}</MenuItem>
            ))}
          </TextField>

          <TextField
            select
            label="الحالة"
            value={formData.condition}
            onChange={(e) => setFormData({...formData, condition: e.target.value})}
          >
            <MenuItem value="new">✨ جديد</MenuItem>
            <MenuItem value="like-new">🔄 شبه جديد</MenuItem>
            <MenuItem value="used">📦 مستعمل</MenuItem>
          </TextField>

          <Button variant="outlined" component="label" sx={{ py: 2 }}>
            📷 اختيار صور
            <input type="file" hidden multiple accept="image/*" onChange={handleImageChange} />
          </Button>

          {images.length > 0 && (
            <Typography variant="body2" color="primary" align="center">
              تم اختيار {images.length} صورة
            </Typography>
          )}

          <Button type="submit" variant="contained" size="large" sx={{ mt: 2 }}>
            نشر المنتج
          </Button>
        </Box>
      </Paper>
    </Container>
  );
}
